import{_ as s,o,c as e,a2 as a}from"./chunks/framework.BWuWLRhz.js";const d="/assets/15-prompt-before-after@2x.B2oY7VMM.png",u=JSON.parse('{"title":"15 · 怎么提问和给指令：把话说到 Claude 心坎里","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/15-prompting.md","filePath":"claude-code/15-prompting.md"}'),n={name:"claude-code/15-prompting.md"};function r(p,t,l,i,g,c){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="_15-·-怎么提问和给指令-把话说到-claude-心坎里" tabindex="-1">15 · 怎么提问和给指令：把话说到 Claude 心坎里 <a class="header-anchor" href="#_15-·-怎么提问和给指令-把话说到-claude-心坎里" aria-label="Permalink to &quot;15 · 怎么提问和给指令：把话说到 Claude 心坎里&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 [14 交互界面与快捷键] 教你把手指放对地方——光标、回车、Esc、斜杠命令都熟了。这一篇换个层面：手知道往哪按了，<strong>嘴还得知道怎么说</strong>。同样一个需求，话说得好不好，Claude 干出来的活儿天差地别。</p></blockquote><p>说句不太中听的实话：很多人刚上手 Claude Code 那阵子，<strong>都把它当搜索引擎使</strong>。</p><p>设想这样一个场景：项目里一个函数报错，你啪地甩过去一句「<strong>修一下这个 bug</strong>」，连哪个文件、什么报错都没说，回车，等着看戏。结果它「猜」了个它以为的 bug，改了三个文件，<strong>没一个是你真正想修的那处</strong>。你盯着满屏 diff 一脸懵，心里还嘀咕「这 AI 不行啊」。</p><p>回头一想就明白了——<strong>不行的不是它</strong>。问题压根不在 Claude，在那句话太烂：信息量约等于零，它只能靠脑补。脑补错了，能怪谁？</p><p>这么说吧：<strong>Claude Code 的天花板，很大程度上是被你的提问方式锁死的</strong>。同一个模型、同一个项目，会提需求的人三句话搞定，不会提的人来回返工五轮还一肚子火。今天就把「怎么把一句话需求说清楚」这套通用说话法则给你讲透——<strong>不是教你背模板，是教你想明白「Claude 到底需要知道什么才不跑偏」</strong>。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一张「烂提问 vs 好提问」对照表，照着改，返工率立降</li><li>四条提需求的硬核心法：具体、给上下文、给验收标准、复杂任务先列计划</li><li><code>@</code> 引用文件把范围圈准的正确姿势</li><li>一个可照做的「同一需求两种说法」实验，亲眼看出差距</li></ul><hr><h2 id="_01-烂提问到底烂在哪" tabindex="-1">01 烂提问到底烂在哪 <a class="header-anchor" href="#_01-烂提问到底烂在哪" aria-label="Permalink to &quot;01 烂提问到底烂在哪&quot;">​</a></h2><p>把上面那次翻车摊开看。「修一下这个 bug」这句话，<strong>站在 Claude 的角度，信息缺得离谱</strong>：</p><ul><li>哪个 bug？它得自己猜你说的是哪处。</li><li>哪个文件？它得满项目翻。</li><li>期望的正确行为是啥？它根本不知道，只能按「一般来说应该怎样」脑补。</li></ul><p><strong>类比：带新人。</strong> 你跟一个刚入职的实习生说「把那个东西弄一下」，他能弄对才有鬼。换成「把首页右上角那个登录按钮，颜色从灰色改成品牌蓝 <code>#1A73E8</code>」，他闭着眼都能做对。<strong>指令越具体，新人越不跑偏；你越是甩一句模糊的，他越得猜，猜错的概率越大。</strong> Claude 一模一样。</p><p>来看官方文档里反复强调的这组对照（按官方的意思译成了中文）：</p><table tabindex="0"><thead><tr><th>场景</th><th>❌ 烂提问</th><th>✅ 好提问</th></tr></thead><tbody><tr><td><strong>修 bug</strong></td><td>「修一下登录的错误」</td><td>「用户报告会话超时后登录失败。检查 <code>src/auth/</code> 里的认证流程，重点看 token 刷新。先写一个能复现问题的失败测试，再修它」</td></tr><tr><td><strong>写测试</strong></td><td>「给 <code>foo.py</code> 加测试」</td><td>「给 <code>foo.py</code> 写测试，覆盖用户已登出的边界情况，别用 mock」</td></tr><tr><td><strong>问代码</strong></td><td>「<code>ExecutionFactory</code> 这破 api 怎么设计成这样？」</td><td>「翻一下 <code>ExecutionFactory</code> 的 git 历史，总结它的 api 是怎么一步步演变成现在这样的」</td></tr><tr><td><strong>加功能</strong></td><td>「加个日历组件」</td><td>「先看主页上现有组件怎么实现的，<code>HotDogWidget.php</code> 是个好例子。照这个模式实现一个日历组件，让用户选月份、能前后翻年。除了代码库里已有的库，别引新库」</td></tr></tbody></table><p>看出门道没？<strong>好提问全在干一件事：把 Claude 本来要靠猜的东西，提前喂给它。</strong></p><blockquote><p>💡 <strong>一句话总结</strong>：烂提问烂在「信息缺口全靠 Claude 脑补」，<strong>好提问就是把它要猜的，你提前说清楚</strong>。</p></blockquote><p><img src="'+d+`" alt="烂提问 vs 好提问：同一个需求两种问法"></p><p>这张 Before/After 把同一个需求的两种问法摆到一起：<strong>左边模糊提问，Claude 只能脑补、反问一堆；右边把范围、上下文（<code>@文件</code>）、验收标准三件套给齐，它一次命中、直接跑测试通过</strong>。差距不在 Claude，在你怎么说。</p><hr><h2 id="_02-心法一-具体-模糊" tabindex="-1">02 心法一：具体 &gt; 模糊 <a class="header-anchor" href="#_02-心法一-具体-模糊" aria-label="Permalink to &quot;02 心法一：具体 &gt; 模糊&quot;">​</a></h2><p>这是四条心法里最重要的一条，没有之一。</p><p>官方文档里有句话特别值得记住，原话是：</p><blockquote><p>你的指令越精确，你需要的更正就越少。</p></blockquote><p>翻译成大白话：<strong>前面多说一句，后面少返工三轮。</strong> 你以为「省事」是少打几个字，其实少打的那几个字，最后都变成来回拉扯的代价加倍还给你。</p><p><strong>具体到什么程度？</strong> 三个维度往里塞：</p><p><strong>第一，圈定范围</strong>——哪个文件、哪个函数、哪个场景。别让它满项目大海捞针。</p><p><strong>第二，说清约束</strong>——「别引新库」「保持向后兼容」「别动测试文件」。你不说，它就按自己的偏好来，回头未必合你心意。</p><p><strong>第三，指个参照</strong>——「照 <code>HotDogWidget.php</code> 那个模式来」。这招实测下来最省心：<strong>与其用语言描述你想要的风格，不如直接甩给它一个你已经满意的现成例子</strong>，它照着抄，八九不离十。</p><blockquote><p>这里有个反直觉的例外得讲清楚：<strong>模糊提问不是绝对的错。</strong> 当你在「探索阶段」、自己也没想好方向时，一句开放的「你觉得这个文件有什么可以改进的？」反而能炸出一些你压根没想到要问的东西。官方原话叫「当你在探索并能够改正方向时，模糊的提示可能很有用」。<strong>规律是：要结果时往死里具体，找灵感时故意留白。</strong></p></blockquote><p>做一个小工具的时候很容易踩到这个边界——一开始就想看看 Claude 怎么理解那摊乱代码，故意问得很泛，它给的几个改进点确实有启发；可一旦心里有了明确目标，再用模糊提问就纯属浪费回合了，它每次都得重新猜你到底要啥。</p><blockquote><p>💡 <strong>一句话总结</strong>：要确定结果就往死里具体（范围 + 约束 + 参照），<strong>只有在主动找灵感时才故意留白</strong>。</p></blockquote><hr><h2 id="_03-心法二-给上下文-别让它瞎猜" tabindex="-1">03 心法二：给上下文，别让它瞎猜 <a class="header-anchor" href="#_03-心法二-给上下文-别让它瞎猜" aria-label="Permalink to &quot;03 心法二：给上下文，别让它瞎猜&quot;">​</a></h2><p>具体之外，第二招是<strong>把「料」直接喂到它嘴边</strong>，而不是用嘴描述「料」在哪。</p><p>最高频的两个动作，记住就够用一大半：</p><p><strong>第一，用 <code>@</code> 引用文件。</strong> 在输入框打 <code>@</code>，会弹出文件路径补全，选中后<strong>这个文件的完整内容会被直接塞进对话</strong>——Claude 不用先去找、再去读，省一步还不会找错。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>参考 @src/types/user.ts 里的类型定义，给 UserService 补上类型注解</span></span></code></pre></div><p>这比「项目里有个 user 类型文件，你去找找」靠谱一万倍。官方文档明确写了 <code>@</code> 引用「在响应前读取文件的完整内容」。</p><p><strong>类比：USB 接口。</strong> <code>@</code> 就像把一块「文件 U 盘」直接插进 Claude 的工作台——插上即用，它要的资料一秒到位；你光用嘴说「资料在三楼档案室第二个柜子」，它还得自己跑一趟，跑错了更耽误事。</p><p><strong>第二，报错直接整段贴。</strong> 这条值得练成肌肉记忆——遇到 traceback，<strong>别概括「它报了个空指针」，把完整堆栈原样糊进去</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>运行时报了这个错，帮我定位原因：</span></span>
<span class="line"><span>TypeError: Cannot read properties of null (reading &#39;userId&#39;)</span></span>
<span class="line"><span>    at getUserProfile (src/services/user.ts:42:18)</span></span>
<span class="line"><span>    at async ProfileController.getProfile (src/controllers/profile.ts:15:20)</span></span></code></pre></div><p>为啥要整段贴？因为堆栈里<strong>文件名、行号、调用链全有</strong>，Claude 顺着 <code>user.ts:42</code> 就能精准定位。你概括一遍，等于把这些关键坐标全删了，它又得从头猜。</p><table tabindex="0"><thead><tr><th>你想给的料</th><th>❌ 用嘴描述</th><th>✅ 直接喂</th></tr></thead><tbody><tr><td>某个文件的内容</td><td>「项目里有个处理认证的文件」</td><td><code>@src/auth/session.ts</code></td></tr><tr><td>一段报错</td><td>「它报了个 undefined 的错」</td><td>把完整 traceback 原样贴进去</td></tr><tr><td>一个 UI 问题</td><td>「按钮位置不对」</td><td>直接粘截图（Claude 支持读图）</td></tr><tr><td>一份接口规范</td><td>「按我们的 API 规范来」</td><td><code>@docs/api-spec.md</code></td></tr></tbody></table><p>一句话：<strong>凡是能「贴」的，绝不用「说」。</strong> Claude 读原始材料，永远比读你对材料的二手转述准。</p><blockquote><p>💡 <strong>一句话总结</strong>：用 <code>@</code> 把文件、用粘贴把报错和截图<strong>直接怼到它面前</strong>，别让它顺着你的描述去猜。</p></blockquote><hr><h2 id="_04-心法三-给一个「可验证」的成功标准" tabindex="-1">04 心法三：给一个「可验证」的成功标准 <a class="header-anchor" href="#_04-心法三-给一个「可验证」的成功标准" aria-label="Permalink to &quot;04 心法三：给一个「可验证」的成功标准&quot;">​</a></h2><p>这条最容易被忽略，但威力巨大：<strong>你得让 Claude 知道「干成什么样算成功」，而且这个标准最好它自己能验。</strong></p><p>为什么关键？官方文档点破了底层逻辑——</p><blockquote><p>当工作看起来完成时，Claude 会停止。没有它可以运行的检查，「看起来完成」是唯一可用的信号，你成为验证循环：每个错误都在等待你注意到它。</p></blockquote><p>啥意思？你不给标准，Claude 凭「感觉差不多了」就收工，<strong>真正帮它兜底验收的人是你</strong>，每个漏洞都得你亲自逮。可一旦你给它一个能跑出「通过 / 失败」的检查，<strong>这个循环就自己闭合了</strong>：它干完 → 跑检查 → 看结果 → 没过就接着改，根本不用你盯。</p><p>对比一下就懂了：</p><table tabindex="0"><thead><tr><th>任务</th><th>❌ 没验收标准</th><th>✅ 给了可验证标准</th></tr></thead><tbody><tr><td>写函数</td><td>「实现一个校验邮箱的函数」</td><td>「写一个 <code>validateEmail</code> 函数。示例用例：<code>user@example.com</code> 为真、<code>invalid</code> 为假、<code>user@.com</code> 为假。写完跑测试」</td></tr><tr><td>改 UI</td><td>「让这个仪表盘好看点」</td><td>「[贴设计稿] 照这个实现，然后对结果截图、跟原稿比对，列出差异并修掉」</td></tr><tr><td>修构建</td><td>「构建挂了」</td><td>「构建报这个错：[贴报错]。修它并验证构建通过。解决根本原因，别把错误压下去」</td></tr></tbody></table><p>注意最后一行那句「<strong>解决根本原因，别把错误压下去</strong>」——这是吃过亏才学会加的一句。不写这句，它有时候会图省事直接给你 <code>try/except</code> 一裹、或者加个 <code>@ts-ignore</code> 把红线消掉，<strong>报错是没了，病根还在</strong>。</p><p><strong>进阶玩法：<code>/goal</code> 把验收标准变成「不达标不收工」。</strong>（需要 Claude Code v2.1.139 或更高版本）普通提问里写验收标准，是「这一轮跑一下」；而 <code>/goal</code> 是把标准<strong>钉成整个会话的目标</strong>——每跑完一轮，一个小模型（默认 Haiku）会按你的条件复查一遍，<strong>没达成就自动开下一轮，不把控制权还给你</strong>，直到条件满足才停。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/goal test/auth 里所有测试通过，并且 lint 这步是干净的</span></span></code></pre></div><p>有个用 <code>/goal</code> 的关键细节别踩坑：<strong>那个评估小模型只看 Claude 在对话里「展示」出来的东西，它自己不会去跑命令、读文件</strong>。所以你的条件得是 Claude 自己的输出能证明的——「<code>test/auth</code> 测试全过」之所以成立，是因为 Claude 会真的去跑测试，结果打印在对话里，评估模型才读得到。<strong>你写「代码质量很高」这种没法从输出里看出来的，它判不了。</strong></p><blockquote><p>💡 <strong>一句话总结</strong>：给它一个能跑出通过 / 失败的检查（测试、截图比对、构建退出码），<strong>循环就自己闭合</strong>；想让它「不达标不撒手」，上 <code>/goal</code>。</p></blockquote><hr><h2 id="_05-心法四-复杂任务-先让它列计划再动手" tabindex="-1">05 心法四：复杂任务，先让它列计划再动手 <a class="header-anchor" href="#_05-心法四-复杂任务-先让它列计划再动手" aria-label="Permalink to &quot;05 心法四：复杂任务，先让它列计划再动手&quot;">​</a></h2><p>最后一条，专治「大活儿」：<strong>遇到改动大、跨多文件、或者你自己也吃不准方向的任务，别让它上来就闷头写——先让它列个计划，你过一眼再放行。</strong></p><p>这事第 06 篇（套餐与计费）埋过伏笔，这里说透为什么。官方文档的判断很干脆：</p><blockquote><p>让 Claude 直接跳到编程可能会产生解决错误问题的代码。</p></blockquote><p>说白了，<strong>先探索、再规划、最后编程</strong>——把「想清楚」和「动手干」拆开，免得它在错误的方向上一路狂奔，等你发现时已经改了一堆。</p><p><strong>类比：装修先出图纸再砸墙。</strong> 没有哪个靠谱师傅二话不说抄起锤子就砸承重墙。他得先跟你确认「这面墙拆、这里走线、水管改道」，你点头了再开工。<strong>计划，就是 Claude 砸墙前递给你的那张图纸</strong>——图纸上发现不对，改两笔的成本，远低于墙都砸了再返工。</p><p>怎么让它先出图纸？两个办法：</p><p><strong>办法一，嘴上说清「先别改」。</strong> 在普通对话里加一句限定就行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想给设置页加个深色模式开关。先告诉我要动哪些文件、改动思路是什么，</span></span>
<span class="line"><span>这一步先别改任何代码。</span></span></code></pre></div><p><strong>办法二，切到 Plan Mode（计划模式）。</strong> 这是 Claude Code 专门的「只读规划」档——它会读文件、提方案，<strong>但你批准前它一个字都不落盘</strong>。进入方式：会话里按 <code>Shift + Tab</code>（按一两下循环到 Plan Mode），模式会在 <code>default → acceptEdits → plan</code> 之间轮转。如果只想让某一条提示用 Plan Mode 跑、不切换整个会话，在那条消息前加 <code>/plan</code> 前缀即可。</p><p>不过官方也给了个很实在的提醒，<strong>别走极端把啥都拿去规划</strong>：</p><blockquote><p>对于范围明确且修复很小的任务（如修复拼写错误、添加日志行或重命名变量），要求 Claude 直接执行。当你对方法不确定、更改修改多个文件或你不熟悉被修改的代码时，规划最有用。<strong>如果你能用一句话描述 diff，跳过计划。</strong></p></blockquote><p>最实用的土办法就是这最后半句：<strong>「能不能一句话说清这次改完长啥样？」能，直接干；卡壳了，说明这活儿够复杂，先让它列计划。</strong> 改个错别字也走 Plan Mode，纯属给自己加戏。</p><blockquote><p>💡 <strong>一句话总结</strong>：拿不准 / 跨多文件 / 不熟的代码 → 先让它列计划（一句「先别改」或 <code>Shift+Tab</code> 进 Plan Mode）；<strong>一句话能说清 diff 的小活儿，直接干</strong>。</p></blockquote><hr><h2 id="_06-动手-同一个需求-两种说法见真章" tabindex="-1">06 动手：同一个需求，两种说法见真章 <a class="header-anchor" href="#_06-动手-同一个需求-两种说法见真章" aria-label="Permalink to &quot;06 动手：同一个需求，两种说法见真章&quot;">​</a></h2><p>光听道理不解渴，咱们做个<strong>能亲眼看出差距</strong>的小实验。准备一个三行的玩具文件就行，不依赖你任何现成项目。</p><p><strong>第一步：建个有「坑」的玩具文件</strong>（Mac / Linux）</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prompt-demo</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prompt-demo</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;def average(nums):</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return sum(nums) / len(nums)&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stats.py</span></span></code></pre></div><p>Windows 用户：<code>mkdir prompt-demo</code>、<code>cd prompt-demo</code> 照敲，<code>stats.py</code> 用记事本新建并贴入那两行。</p><p><strong>这个函数有个坑</strong>：传进来空列表 <code>[]</code> 时，<code>len(nums)</code> 是 0，会触发「除以零」崩溃。我们就拿它当试验田。</p><p><strong>第二步：在项目目录里启动 Claude</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>预期</strong>：出现欢迎屏幕，底部有输入框。</p><p><strong>第三步：先用「烂提问」，感受一下它怎么脑补</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@stats.py 帮我改改这个函数</span></span></code></pre></div><p><strong>预期</strong>：Claude 大概率会「猜」你想干啥——也许加类型注解、也许加文档字符串，<strong>但它不知道你真正在意的是那个空列表崩溃</strong>，方向全凭运气。这就是模糊提问的代价：<strong>它在替你做决定。</strong></p><p><strong>第四步：换「好提问」——具体 + 上下文 + 验收标准三件套全上</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@stats.py 里的 average 函数有个 bug：传入空列表时会因为除以零而崩溃。</span></span>
<span class="line"><span>期望行为是空列表返回 0。</span></span>
<span class="line"><span>帮我修复，并补一个测试：average([]) 应该返回 0、average([2, 4]) 应该返回 3。</span></span>
<span class="line"><span>写完把测试跑一遍，确认通过。</span></span></code></pre></div><p><strong>预期</strong>：这一次 Claude 的动作链条清清楚楚——定位空列表分支 → 加上判空返回 0 → 写出你点名的两个测试用例 → 真的去跑测试 → 把通过结果摆给你看。<strong>它不再猜你要啥，因为你把「修哪、改成怎样、怎么算成功」全说死了。</strong></p><p><strong>第五步：退出，看改动落没落地</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stats.py</span></span></code></pre></div><p>（Windows PowerShell 用 <code>type stats.py</code>）</p><p><strong>预期</strong>：<code>stats.py</code> 里出现了对空列表的判断（类似 <code>if not nums: return 0</code>）。<strong>和你第四步要求的对得上 = 你已经摸到「把话说清」的手感了。</strong></p><p>把两次提问并排放一起，差距一目了然：</p><table tabindex="0"><thead><tr><th></th><th>第三步 ❌ 烂提问</th><th>第四步 ✅ 好提问</th></tr></thead><tbody><tr><td>改哪</td><td>没说，它满文件猜</td><td>点名 <code>average</code> 函数</td></tr><tr><td>改成啥样</td><td>没说，凭它发挥</td><td>空列表返回 0，写死了</td></tr><tr><td>怎么算成功</td><td>没标准，它「感觉」完了就停</td><td>两个测试用例 + 跑一遍验证</td></tr><tr><td>你的体验</td><td>盯着 diff 纳闷「这不是我要的」</td><td>它按你的剧本演，一遍过</td></tr></tbody></table><blockquote><p>💡 <strong>一句话总结</strong>：同一个文件、同一个 bug，烂提问让 Claude 替你做决定，好提问把「改哪、改成怎样、怎么算成功」全说死——<strong>亲手跑一遍这两步，差距比看十遍道理都直观</strong>。</p></blockquote><hr><h2 id="_07-小结" tabindex="-1">07 小结 <a class="header-anchor" href="#_07-小结" aria-label="Permalink to &quot;07 小结&quot;">​</a></h2><p>这一篇就讲了一件事：<strong>怎么把一句话需求，说到 Claude 能精准接住。</strong></p><p>四条心法收个口，背不下来就记这张表：</p><table tabindex="0"><thead><tr><th>心法</th><th>一句话</th><th>怎么落地</th></tr></thead><tbody><tr><td><strong>具体 &gt; 模糊</strong></td><td>范围 + 约束 + 参照都说清</td><td>「改 <code>average</code>，别引新库，照 <code>xxx</code> 的模式」</td></tr><tr><td><strong>给上下文</strong></td><td>能贴的绝不用嘴说</td><td><code>@文件</code>、整段贴报错、粘截图</td></tr><tr><td><strong>给验收标准</strong></td><td>让它自己能验「成没成」</td><td>给测试用例、要它跑一遍；狠的上 <code>/goal</code></td></tr><tr><td><strong>先列计划</strong></td><td>大活儿先看图纸再砸墙</td><td>一句「先别改」或 <code>Shift+Tab</code> 进 Plan Mode</td></tr></tbody></table><p><strong>你现在应该能：</strong> 把一句模糊的「帮我改改」翻译成 Claude 真正接得住的需求——圈准范围、喂足上下文、给出可验证的成功标准，复杂的还会先让它列计划。<strong>这套说话法则，是你之后用 Claude Code 一切操作的「内功」</strong>——功能再花哨，喂进去的提问烂，出来的活儿也好不了。</p><blockquote><p>反过来想一个问题留给你：既然「把话说清」这么重要，那有些规矩（比如「这个项目永远别引新库」「测试一律放 <code>tests/</code> 目录」）你<strong>每次都得重说一遍</strong>吗？有没有办法让 Claude「记住」，省得天天复读？</p></blockquote><hr><p>下一篇 <strong>16「常见工作流」</strong>——这一篇教的是「怎么把一句话说清」的通用法则，下一篇就把它落到四类最高频的具体活儿上：探索陌生代码库、修 bug、重构、写测试，每一类给你一套能照搬的标准打法。法则有了，该看招式了。</p>`,106)])])}const b=s(n,[["render",r]]);export{u as __pageData,b as default};
